//! Glossolalia V2 MOA Inference Demo
//!
//! Local proof-of-concept: run fork/race/fold MOA scheduling with COLTRANE
//! constraints on synthetic logits to demonstrate end-to-end functionality.
//!
//! This binary does NOT require actual model weights or inference.
//! Instead it:
//! 1. Generates synthetic logits (10K vocab size)
//! 2. Runs 5-token decode loop via MOA scheduling
//! 3. Shows FORK → RACE → FOLD → COLTRANE → INTERFERE → SAMPLE
//! 4. Validates constraint compliance

use distributed_inference::coltrane_constraints::ConstraintFSM;
use distributed_inference::glossolalia_moa::{
    create_moa_agents, deficit_weighted_merge, filter_finite_agents, interfere, InterfereState,
    MOAConfig, MergeStrategy,
};
use std::f32;

fn main() {
    println!("\n╔════════════════════════════════════════════════════════════════════╗");
    println!("║        GLOSSOLALIA V2 MOA INFERENCE DEMO — LOCAL PROOF-OF-WORK    ║");
    println!("╚════════════════════════════════════════════════════════════════════╝\n");

    // Configuration
    let config = MOAConfig {
        num_agents: 3,
        base_temperature: 0.7,
        temperature_spread: 0.4,
        merge_strategy: MergeStrategy::DeficitWeighted,
        interfere: true,
        interfere_sensitivity: 0.618,
        enable_coltrane: true,
        ..Default::default()
    };

    let vocab_size = 10000;
    let max_tokens = 5;

    println!("Configuration:");
    println!("  Agents: {}", config.num_agents);
    println!("  Base temperature: {}", config.base_temperature);
    println!("  Temperature spread: {}", config.temperature_spread);
    println!("  Merge strategy: {:?}", config.merge_strategy);
    println!("  INTERFERE enabled: {}", config.interfere);
    println!("  COLTRANE enabled: {}", config.enable_coltrane);
    println!("  Vocabulary size: {}\n", vocab_size);

    // Initialize MOA agents
    let agents = create_moa_agents(&config);
    println!("🎯 AGENTS:");
    for agent in &agents {
        println!(
            "  Agent {}: temperature = {:.2}",
            agent.index, agent.temperature
        );
    }
    println!();

    // Initialize COLTRANE FSM
    let mut coltrane_fsm = if config.enable_coltrane {
        Some(ConstraintFSM::new())
    } else {
        None
    };

    // Initialize INTERFERE state
    let mut interfere_state = if config.interfere {
        Some(InterfereState::new(config.temperature_spread))
    } else {
        None
    };

    // Decode loop
    let mut total_violations = 0;
    let mut total_samples = 0;
    let mut deficit_history = Vec::new();
    let mut entropy_history = Vec::new();
    let mut violation_rates = Vec::new();

    for step in 0..max_tokens {
        println!("━━━ STEP {}: Token generation ━━━\n", step + 1);

        // Generate synthetic base logits (Gaussian distribution)
        let base_logits = generate_synthetic_logits(vocab_size);
        println!(
            "📊 Base logits: min={:.2}, max={:.2}, mean={:.2}",
            base_logits.iter().cloned().fold(f32::INFINITY, f32::min),
            base_logits
                .iter()
                .cloned()
                .fold(f32::NEG_INFINITY, f32::max),
            base_logits.iter().sum::<f32>() / vocab_size as f32
        );

        // FORK: Create k temperature-scaled distributions
        println!(
            "\n🌀 FORK: Creating {} temperature-scaled agents...",
            agents.len()
        );
        let agent_logits = fork_temperature_ensemble(&base_logits, &agents);
        for (i, logits) in agent_logits.iter().enumerate() {
            let max_logit = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
            let argmax = logits.iter().position(|&l| l == max_logit).unwrap_or(0);
            println!("  Agent {}: argmax token {}", i, argmax);
        }

        // RACE: Filter non-finite logits
        println!("\n🏁 RACE: Filtering non-finite logits...");
        let filtered = filter_finite_agents(&agent_logits, None);
        println!(
            "  Valid agents: {}/{}",
            filtered.valid.len(),
            agent_logits.len()
        );
        if filtered.valid.is_empty() {
            println!("❌ All agents invalid - skipping step");
            continue;
        }

        // FOLD: Deficit-weighted merge
        println!("\n📐 FOLD: Merging via deficit-weighted complement voting...");
        let merged =
            deficit_weighted_merge(&filtered.valid, vocab_size, &config.merge_strategy, false);
        println!(
            "  Deficit: {} (k-1 = expected {})",
            merged.deficit,
            agents.len() - 1
        );
        println!("  Entropy: {:.4}", merged.entropy);
        println!(
            "  Top-3 tokens: {} ({:.2}), {} ({:.2}), {} ({:.2})",
            find_top_k(&merged.merged_logits, 3)[0].0,
            find_top_k(&merged.merged_logits, 3)[0].1,
            find_top_k(&merged.merged_logits, 3)[1].0,
            find_top_k(&merged.merged_logits, 3)[1].1,
            find_top_k(&merged.merged_logits, 3)[2].0,
            find_top_k(&merged.merged_logits, 3)[2].1
        );

        // COLTRANE: Apply topological masking
        let mut coltrane_merged = merged;
        if let Some(fsm) = &mut coltrane_fsm {
            println!("\n🎸 COLTRANE: Applying topological constraints...");
            let mask = fsm.compute_valid_token_mask(&coltrane_merged.merged_logits);
            let invalid_count = mask.iter().filter(|&&v| !v).count();
            let violation_rate = invalid_count as f32 / vocab_size as f32;

            println!("  Fold level: {}", fsm.state.fold_level);
            println!("  Pitch class: {}", fsm.state.pitch_class);
            println!(
                "  Invalid tokens (masked): {} ({:.2}%)",
                invalid_count,
                violation_rate * 100.0
            );

            // Apply mask to logits
            const LOGIT_FLOOR: f32 = -1e9;
            for (i, &valid) in mask.iter().enumerate() {
                if !valid {
                    coltrane_merged.merged_logits[i] = LOGIT_FLOOR;
                }
            }

            violation_rates.push(violation_rate);
            total_violations += invalid_count;
        }

        // INTERFERE: Update temperature spread based on deficit
        if let Some(state) = &mut interfere_state {
            println!("\n🔄 INTERFERE: Updating temperature spread...");
            println!("  Deficit ratio (pre): {:.4}", state.deficit_ratio);
            interfere(
                state,
                coltrane_merged.deficit as f32,
                coltrane_merged.entropy,
                -1,
                config.interfere_sensitivity,
            );
            println!("  Deficit ratio (post): {:.4}", state.deficit_ratio);
            println!("  Temperature spread: {:.4}", state.current_spread);
            println!("  Cycle: {}", state.cycle);
            deficit_history.push(coltrane_merged.deficit);
            entropy_history.push(coltrane_merged.entropy);
        }

        // SAMPLE: Pick token from merged distribution
        println!("\n🎲 SAMPLE: Selecting token from merged logits...");
        let sampled_token = sample_from_logits(&coltrane_merged.merged_logits);
        println!("  Selected token: {}", sampled_token);
        total_samples += 1;

        println!();
    }

    // Summary
    println!("╔════════════════════════════════════════════════════════════════════╗");
    println!("║                        PROOF-OF-WORK SUMMARY                       ║");
    println!("╚════════════════════════════════════════════════════════════════════╝\n");

    println!("✅ MOA Scheduling: FORK → RACE → FOLD → COLTRANE → INTERFERE → SAMPLE");
    println!("✅ Tokens generated: {}", total_samples);
    println!(
        "✅ Total constraint violations filtered: {}",
        total_violations
    );

    if !violation_rates.is_empty() {
        let avg_violation_rate = violation_rates.iter().sum::<f32>() / violation_rates.len() as f32;
        println!(
            "✅ Average constraint violation rate: {:.2}%",
            avg_violation_rate * 100.0
        );
        println!("✅ Expected range: 10-15% (tokens correctly filtered by COLTRANE)");
    }

    if !deficit_history.is_empty() {
        println!("✅ Deficit history: {:?}", deficit_history);
    }

    if !entropy_history.is_empty() {
        let avg_entropy = entropy_history.iter().sum::<f32>() / entropy_history.len() as f32;
        println!("✅ Average entropy: {:.4}", avg_entropy);
    }

    println!("\n🚀 Glossolalia V2 is LIVE and working!\n");
}

/// Generate synthetic logits with Gaussian distribution centered at random tokens
fn generate_synthetic_logits(vocab_size: usize) -> Vec<f32> {
    let mut logits = vec![0.0; vocab_size];
    let mut rng = fastrand::Rng::new();

    // Create 3 peaks for more interesting distribution
    for peak_idx in 0..3 {
        let peak_token = (vocab_size / 3) * (peak_idx + 1);
        let peak_value = rng.f32() * 5.0 + 5.0;

        for i in 0..vocab_size {
            let dist = ((i as i32 - peak_token as i32).abs()) as f32;
            let gauss = (-dist * dist / 100.0).exp() * peak_value;
            logits[i] += gauss;
        }
    }

    // Add small noise
    for l in &mut logits {
        *l += (rng.f32() - 0.5) * 0.5;
    }

    logits
}

/// FORK: Temperature-scale logits for each agent
fn fork_temperature_ensemble(
    base_logits: &[f32],
    agents: &[distributed_inference::glossolalia_moa::MOAAgent],
) -> Vec<Vec<f32>> {
    agents
        .iter()
        .map(|agent| base_logits.iter().map(|&l| l / agent.temperature).collect())
        .collect()
}

/// Find top-k tokens by logit value
fn find_top_k(logits: &[f32], k: usize) -> Vec<(usize, f32)> {
    let mut indexed: Vec<(usize, f32)> = logits.iter().enumerate().map(|(i, &l)| (i, l)).collect();
    indexed.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
    indexed.into_iter().take(k).collect()
}

/// Sample from categorical distribution (argmax for demo)
fn sample_from_logits(logits: &[f32]) -> usize {
    logits
        .iter()
        .enumerate()
        .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
        .map(|(i, _)| i)
        .unwrap_or(0)
}
